     1→"use client";
     2→
     3→import { cn } from "@/lib/utils";
     4→import { connect } from "echarts";
     5→import { ChevronRight } from "lucide-react";
     6→import React, {
     7→  createContext,
     8→  forwardRef,
     9→  useCallback,
    10→  useContext,
    11→  useEffect,
    12→  useImperativeHandle,
    13→  useMemo,
    14→  useRef,
    15→  useState,
    16→} from "react";
    17→import type { Dashboard, DashboardGroup, GridPos, PanelDescriptor } from "./dashboard-model";
    18→import type {
    19→  DashboardVisualizationComponent,
    20→  RefreshOptions,
    21→} from "./dashboard-visualization-layout";
    22→import { DashboardVisualizationPanel } from "./dashboard-visualization-panel";
    23→import type { TimeSpan } from "./timespan-selector";
    24→
    25→export interface DashboardPanelContainerRef {
    26→  refresh: (timeSpan?: TimeSpan, filterExpression?: string) => void;
    27→}
    28→
    29→/**
    30→ * Interface for child components that can be refreshed by the dashboard.
    31→ * Children that implement this interface will be automatically refreshed
    32→ * when the dashboard is refreshed.
    33→ */
    34→export interface RefreshableChild {
    35→  refresh: (timeSpan?: TimeSpan, filterExpression?: string) => void;
    36→}
    37→
    38→/**
    39→ * Context for dashboard refresh registration.
    40→ * Child components can use the useDashboardRefresh hook to register
    41→ * themselves for automatic refresh when the dashboard refreshes.
    42→ */
    43→interface DashboardRefreshContextValue {
    44→  register: (child: RefreshableChild) => void;
    45→  unregister: (child: RefreshableChild) => void;
    46→}
    47→
    48→const DashboardRefreshContext = createContext<DashboardRefreshContextValue | null>(null);
    49→
    50→/**
    51→ * Hook for child components to register themselves for dashboard refresh.
    52→ * When the dashboard is refreshed, the provided refresh function will be called.
    53→ *
    54→ * @param refreshFn - Function to call when dashboard refreshes
    55→ *
    56→ * @example
    57→ * ```tsx
    58→ * const MyComponent = () => {
    59→ *   const fetchData = useCallback((timeSpan?: TimeSpan) => {
    60→ *     // fetch data...
    61→ *   }, []);
    62→ *
    63→ *   useDashboardRefresh(fetchData);
    64→ *
    65→ *   return <div>...</div>;
    66→ * };
    67→ * ```
    68→ */
    69→export function useDashboardRefresh(
    70→  refreshFn: (timeSpan?: TimeSpan, filterExpression?: string) => void
    71→) {
    72→  const ctx = useContext(DashboardRefreshContext);
    73→
    74→  useEffect(() => {
    75→    if (!ctx) return;
    76→
    77→    const child: RefreshableChild = { refresh: refreshFn };
    78→    ctx.register(child);
    79→
    80→    return () => {
    81→      ctx.unregister(child);
    82→    };
    83→  }, [ctx, refreshFn]);
    84→}
    85→
    86→interface DashboardPanelContainerProps {
    87→  dashboard: Dashboard;
    88→  initialTimeSpan?: TimeSpan;
    89→  initialFilterExpression?: string;
    90→  initialLoading?: boolean;
    91→  onChartSelection?: (
    92→    timeSpan: TimeSpan,
    93→    selection: { name: string; series: string; value: number }
    94→  ) => void;
    95→  /**
    96→   * Children to render below the dashboard panels.
    97→   * Children can use the useDashboardRefresh hook to register
    98→   * themselves for automatic refresh when the dashboard refreshes.
    99→   */
   100→  children?: React.ReactNode;
   101→}
   102→
   103→// Helper function to check if an item is a DashboardGroup
   104→function isDashboardGroup(item: unknown): item is DashboardGroup {
   105→  return (
   106→    typeof item === "object" &&
   107→    item !== null &&
   108→    "title" in item &&
   109→    "charts" in item &&
   110→    Array.isArray((item as { charts: unknown }).charts)
   111→  );
   112→}
   113→
   114→// Helper function to flatten all charts (including charts in groups)
   115→function getAllCharts(charts: (PanelDescriptor | DashboardGroup)[]): PanelDescriptor[] {
   116→  const allCharts: PanelDescriptor[] = [];
   117→  charts.forEach((item) => {
   118→    if (isDashboardGroup(item)) {
   119→      allCharts.push(...item.charts);
   120→    } else {
   121→      allCharts.push(item);
   122→    }
   123→  });
   124→  return allCharts;
   125→}
   126→
   127→const DASHBOARD_MOBILE_BREAKPOINT = 768;
   128→const DASHBOARD_DESKTOP_BREAKPOINT = 1024;
   129→
   130→/** Single source of truth for dashboard grid column counts: mobile | tablet | desktop */
   131→export type DashboardGridColumns = 1 | 6 | 24;
   132→
   133→/**
   134→ * Returns the number of grid columns for the dashboard layout:
   135→ * - 1: mobile (< 768px) – single column
   136→ * - 8: tablet (768px–1023px) – 8 columns
   137→ * - 24: desktop (≥ 1024px) – 24 columns
   138→ */
   139→function useDashboardGridColumns(): DashboardGridColumns {
   140→  const [columns, setColumns] = useState<DashboardGridColumns>(24);
   141→
   142→  useEffect(() => {
   143→    const update = () => {
   144→      const w = window.innerWidth;
   145→      if (w < DASHBOARD_MOBILE_BREAKPOINT) setColumns(1);
   146→      else if (w < DASHBOARD_DESKTOP_BREAKPOINT) setColumns(6);
   147→      else setColumns(24);
   148→    };
   149→    const mqlMobile = window.matchMedia(`(max-width: ${DASHBOARD_MOBILE_BREAKPOINT - 1}px)`);
   150→    const mqlDesktop = window.matchMedia(`(min-width: ${DASHBOARD_DESKTOP_BREAKPOINT}px)`);
   151→    const onChange = () => update();
   152→    mqlMobile.addEventListener("change", onChange);
   153→    mqlDesktop.addEventListener("change", onChange);
   154→    update();
   155→    return () => {
   156→      mqlMobile.removeEventListener("change", onChange);
   157→      mqlDesktop.removeEventListener("change", onChange);
   158→    };
   159→  }, []);
   160→
   161→  return columns;
   162→}
   163→
   164→// Helper function to get gridPos from chart
   165→// All dashboards must be version 3 with gridPos defined
   166→function getGridPos(chart: PanelDescriptor): GridPos {
   167→  if (chart.gridPos) {
   168→    return chart.gridPos;
   169→  }
   170→
   171→  // Fallback for panels without gridPos (should not happen in version 3)
   172→  // This provides a reasonable default to prevent runtime errors
   173→  console.warn(
   174→    `Panel "${chart.titleOption?.title ?? chart.type}" is missing gridPos. Using default.`
   175→  );
   176→  return {
   177→    w: 24,
   178→    h: 6,
   179→  };
   180→}
   181→
   182→// Component to render a panel with grid styling (layout is defined in 24-col base)
   183→interface DashboardGridPanelProps {
   184→  descriptor: PanelDescriptor;
   185→  panelIndex: number;
   186→  isVisible: boolean;
   187→  gridColumns: DashboardGridColumns;
   188→  onSubComponentUpdated: (
   189→    subComponent: DashboardVisualizationComponent | null,
   190→    index: number
   191→  ) => void;
   192→  initialTimeSpan?: TimeSpan;
   193→  initialFilterExpression?: string;
   194→  initialLoading?: boolean;
   195→  isCollapsed: boolean;
   196→  onCollapsedChange: (isCollapsed: boolean) => void;
   197→  onChartSelection?: (
   198→    timeSpan: TimeSpan,
   199→    selection: { name: string; series: string; value: number }
   200→  ) => void;
   201→}
   202→
   203→const DashboardGridPanel: React.FC<DashboardGridPanelProps> = ({
   204→  descriptor: chart,
   205→  panelIndex,
   206→  isVisible,
   207→  gridColumns,
   208→  onSubComponentUpdated,
   209→  initialTimeSpan,
   210→  initialFilterExpression,
   211→  initialLoading,
   212→  isCollapsed,
   213→  onCollapsedChange,
   214→  onChartSelection,
   215→}) => {
   216→  const gridPos = getGridPos(chart);
   217→
   218→  // Use minimal row span (1) when collapsed, full height when expanded
   219→  const effectiveRowSpan = isCollapsed ? 1 : gridPos.h;
   220→
   221→  // Calculate max height based on grid rows: each row is 32px min + 8px gap between rows
   222→  // This ensures the panel doesn't grow beyond its intended height even with gridAutoRows: auto
   223→  const ROW_HEIGHT = 36; // minmax(32px, auto) plus title padding
   224→  const GAP_SIZE = 8; // gap-y-2 = 0.5rem = 8px
   225→  const maxHeight = effectiveRowSpan * ROW_HEIGHT + (effectiveRowSpan - 1) * GAP_SIZE;
   226→
   227→  const gridStyle: React.CSSProperties = {
   228→    display: isVisible ? "block" : "none",
   229→    gridRow: `span ${effectiveRowSpan}`,
   230→    minHeight: 0, // Allow grid item to shrink below content size
   231→  };
   232→
   233→  if (gridColumns === 1) {
   234→    gridStyle.gridColumn = "1 / -1";
   235→  } else {
   236→    // Scale from 24-column base to current grid (8 or 24).
   237→    // On tablet (gridColumns < 24), enforce a minimum span so small panels (e.g. w=3)
   238→    // don't shrink to 1 column and pack 6+ per row; aim for at most 2 panels per row.
   239→    const wScaled = Math.round((gridPos.w / 24) * gridColumns);
   240→    const minSpan = gridColumns < 24 ? Math.ceil(gridColumns / 2) : 1;
   241→    const span = Math.max(minSpan, Math.min(wScaled, gridColumns));
   242→    if (gridPos.x !== undefined) {
   243→      const xScaled = Math.round((gridPos.x / 24) * gridColumns);
   244→      gridStyle.gridColumnStart = xScaled + 1;
   245→      gridStyle.gridColumnEnd = xScaled + 1 + span;
   246→    } else {
   247→      gridStyle.gridColumn = `span ${span}`;
   248→    }
   249→  }
   250→
   251→  if (gridPos.y !== undefined && gridColumns !== 1) {
   252→    gridStyle.gridRowStart = gridPos.y + 1;
   253→    gridStyle.gridRowEnd = gridPos.y + 1 + effectiveRowSpan;
   254→  }
   255→
   256→  // Always constrain height to prevent grid rows from expanding beyond intended size
   257→  gridStyle.maxHeight = `${maxHeight}px`;
   258→  gridStyle.overflow = "hidden";
   259→
   260→  return (
   261→    <div style={gridStyle} className={cn("w-full", isCollapsed ? "h-auto" : "h-full")}>
   262→      <DashboardVisualizationPanel
   263→        descriptor={chart}
   264→        initialTimeSpan={initialTimeSpan}
   265→        initialFilterExpression={initialFilterExpression}
   266→        initialLoading={initialLoading}
   267→        ref={(el) => onSubComponentUpdated(el, panelIndex)}
   268→        onCollapsedChange={onCollapsedChange}
   269→        onChartSelection={onChartSelection}
   270→      />
   271→    </div>
   272→  );
   273→};
   274→
   275→const DashboardPanelContainer = forwardRef<
   276→  DashboardPanelContainerRef,
   277→  DashboardPanelContainerProps
   278→>(
   279→  (
   280→    {
   281→      dashboard,
   282→      initialTimeSpan,
   283→      initialFilterExpression,
   284→      initialLoading,
   285→      onChartSelection,
   286→      children,
   287→    },
   288→    ref
   289→  ) => {
   290→    // Track group collapse states at component level
   291→    const [groupCollapseStates, setGroupCollapseStates] = useState<Map<number, boolean>>(new Map());
   292→    // Track individual panel collapse states
   293→    const [panelCollapseStates, setPanelCollapseStates] = useState<Map<number, boolean>>(new Map());
   294→    const subComponentRefs = useRef<(DashboardVisualizationComponent | null)[]>([]);
   295→
   296→    // Track registered refreshable children
   297→    const registeredChildrenRef = useRef<Set<RefreshableChild>>(new Set());
   298→
   299→    // 1 col mobile, 8 col tablet (e.g. iPad), 24 col desktop
   300→    const gridColumns = useDashboardGridColumns();
   301→
   302→    // Memoize the charts array from the dashboard
   303→    // All dashboards must be version 3 with gridPos defined
   304→    const panels = useMemo(() => dashboard.charts, [dashboard]);
   305→
   306→    // Memoize the panel flattening logic - no x,y calculation needed, CSS Grid handles it
   307→    const { allPanels, groups } = useMemo(() => {
   308→      // Flatten all charts (standalone + from groups) into one list with group tracking
   309→      const flattenPanels: Array<{
   310→        panel: PanelDescriptor;
   311→        groupIndex?: number; // undefined for standalone charts
   312→        group?: DashboardGroup; // reference to group for group panels
   313→      }> = [];
   314→
   315→      // Track group information
   316→      const groupInfos: Array<{
   317→        group: DashboardGroup;
   318→        groupIndex: number;
   319→        startPanelIndex: number; // index in panels where this group's panels start
   320→        endPanelIndex: number; // index in panels where this group's panels end (exclusive)
   321→      }> = [];
   322→
   323→      let groupIndex = 0;
   324→
   325→      // Process charts: flatten panels (no positioning calculation needed)
   326→      panels.forEach((item) => {
   327→        if (isDashboardGroup(item)) {
   328→          const group = item;
   329→          const startPanelIndex = flattenPanels.length;
   330→
   331→          // Add all panels from this group
   332→          group.charts.forEach((chart: PanelDescriptor) => {
   333→            flattenPanels.push({
   334→              panel: chart,
   335→              groupIndex,
   336→              group,
   337→            });
   338→          });
   339→
   340→          // Store group info
   341→          groupInfos.push({
   342→            group,
   343→            groupIndex,
   344→            startPanelIndex,
   345→            endPanelIndex: flattenPanels.length,
   346→          });
   347→
   348→          groupIndex++;
   349→        } else {
   350→          // Standalone chart
   351→          flattenPanels.push({
   352→            panel: item as PanelDescriptor,
   353→          });
   354→        }
   355→      });
   356→
   357→      return { allPanels: flattenPanels, groups: groupInfos };
   358→    }, [panels]);
   359→
   360→    // Initialize group collapse states from dashboard (only once when groups change)
   361→    useEffect(() => {
   362→      groups.forEach((g) => {
   363→        if (!groupCollapseStates.has(g.groupIndex)) {
   364→          setGroupCollapseStates((prev) => {
   365→            const next = new Map(prev);
   366→            next.set(g.groupIndex, g.group.collapsed ?? false);
   367→            return next;
   368→          });
   369→        }
   370→      });
   371→    }, [groups, groupCollapseStates]);
   372→
   373→    // Initialize panel collapse states from descriptors
   374→    useEffect(() => {
   375→      allPanels.forEach((item, index) => {
   376→        if (!panelCollapseStates.has(index)) {
   377→          setPanelCollapseStates((prev) => {
   378→            const next = new Map(prev);
   379→            next.set(index, item.panel.collapsed ?? false);
   380→            return next;
   381→          });
   382→        }
   383→      });
   384→    }, [allPanels, panelCollapseStates]);
   385→
   386→    const toggleGroup = useCallback((groupIndex: number) => {
   387→      setGroupCollapseStates((prev) => {
   388→        const next = new Map(prev);
   389→        next.set(groupIndex, !(next.get(groupIndex) ?? false));
   390→        return next;
   391→      });
   392→    }, []);
   393→
   394→    const onPanelCollapsedChange = useCallback((panelIndex: number, isCollapsed: boolean) => {
   395→      setPanelCollapseStates((prev) => {
   396→        const next = new Map(prev);
   397→        next.set(panelIndex, isCollapsed);
   398→        return next;
   399→      });
   400→    }, []);
   401→
   402→    // Determine which panels should be visible based on group collapse states
   403→    const isPanelVisible = useCallback(
   404→      (panelIndex: number): boolean => {
   405→        const panel = allPanels[panelIndex];
   406→        if (panel.groupIndex === undefined) {
   407→          // Standalone panel - always visible
   408→          return true;
   409→        }
   410→
   411→        // Check if the group this panel belongs to is collapsed
   412→        // If state not initialized yet, check the group's collapsed property
   413→        if (!groupCollapseStates.has(panel.groupIndex)) {
   414→          // State not initialized, use group's default collapsed state
   415→          const group = groups.find((g) => g.groupIndex === panel.groupIndex);
   416→          return !(group?.group.collapsed ?? false);
   417→        }
   418→
   419→        const isCollapsed = groupCollapseStates.get(panel.groupIndex) ?? false;
   420→        return !isCollapsed;
   421→      },
   422→      [allPanels, groupCollapseStates, groups]
   423→    );
   424→
   425→    // Function to connect all chart instances together
   426→    const connectAllCharts = useCallback(() => {
   427→      const chartInstances: echarts.ECharts[] = subComponentRefs.current
   428→        .filter(
   429→          (ref): ref is DashboardVisualizationComponent =>
   430→            ref !== null &&
   431→            typeof (ref as unknown as { getEChartInstance?: () => echarts.ECharts })
   432→              .getEChartInstance === "function"
   433→        )
   434→        .map((ref) => {
   435→          const component = ref as unknown as { getEChartInstance: () => echarts.ECharts };
   436→          return component.getEChartInstance();
   437→        })
   438→        .filter((echartInstance) => echartInstance !== undefined);
   439→
   440→      if (chartInstances.length === 0) {
   441→        return;
   442→      }
   443→
   444→      const allCharts = getAllCharts(panels);
   445→      const chartNumber = allCharts.filter(
   446→        (chart: PanelDescriptor) => chart.type !== "table"
   447→      ).length;
   448→      if (chartInstances.length === chartNumber) {
   449→        // Connect all echarts together on this page
   450→        connect(chartInstances);
   451→      }
   452→    }, [panels]);
   453→
   454→    // Callback when the sub component is mounted or unmounted
   455→    const onSubComponentUpdated = useCallback(
   456→      (subComponent: DashboardVisualizationComponent | null, index: number) => {
   457→        subComponentRefs.current[index] = subComponent;
   458→        connectAllCharts();
   459→      },
   460→      [connectAllCharts]
   461→    );
   462→
   463→    const refreshAllCharts = useCallback(
   464→      (newTimeSpan?: TimeSpan, newFilterExpression?: string) => {
   465→        const refreshParam: RefreshOptions = {
   466→          timeSpan: newTimeSpan ?? initialTimeSpan,
   467→          filterExpression: newFilterExpression ?? initialFilterExpression,
   468→
   469→          // Use forceRefresh to ensure refresh happens even when timeSpan/filterExpression haven't changed
   470→          // This is important for clicking refresh button multiple times with the same parameters
   471→          forceRefresh: true,
   472→        };
   473→
   474→        subComponentRefs.current.forEach((chart) => {
   475→          if (chart !== null) {
   476→            chart.refresh(refreshParam);
   477→          }
   478→        });
   479→
   480→        // Also refresh all registered child components
   481→        registeredChildrenRef.current.forEach((child) => {
   482→          child.refresh(
   483→            newTimeSpan ?? initialTimeSpan,
   484→            newFilterExpression ?? initialFilterExpression
   485→          );
   486→        });
   487→      },
   488→      [initialTimeSpan, initialFilterExpression]
   489→    );
   490→
   491→    // Expose refresh method via imperative handle
   492→    useImperativeHandle(
   493→      ref,
   494→      () => ({
   495→        refresh: (timeSpan?: TimeSpan, filterExpression?: string) => {
   496→          refreshAllCharts(timeSpan, filterExpression);
   497→        },
   498→      }),
   499→      [refreshAllCharts]
   500→    );
   501→
   502→    // Context value for child registration
   503→    const contextValue = useMemo<DashboardRefreshContextValue>(
   504→      () => ({
   505→        register: (child: RefreshableChild) => {
   506→          registeredChildrenRef.current.add(child);
   507→        },
   508→        unregister: (child: RefreshableChild) => {
   509→          registeredChildrenRef.current.delete(child);
   510→        },
   511→      }),
   512→      []
   513→    );
   514→
   515→    return (
   516→      <DashboardRefreshContext.Provider value={contextValue}>
   517→        <div className="h-full flex flex-col overflow-hidden">
   518→          {/* Dashboard section - scrollable */}
   519→          <div className="flex-1 overflow-y-auto overflow-x-hidden">
   520→            {panels &&
   521→              panels.length > 0 &&
   522→              (() => {
   523→                // All dashboards are upgraded to version 3, so we always use CSS Grid layout
   524→                // Grafana's approach: flatten all panels into one grid, render group headers as special items
   525→
   526→                return (
   527→                  <div
   528→                    className="grid gap-x-2 gap-y-2"
   529→                    style={{
   530→                      gridTemplateColumns:
   531→                        gridColumns === 1 ? "1fr" : `repeat(${gridColumns}, minmax(0, 1fr))`,
