// Generate react-grid-layout layouts from panel descriptors
function generateLayoutsFromPanels(
  allPanels: Array<{ panel: PanelDescriptor; groupIndex?: number }>,
  gridColumns: DashboardGridColumns
): Layouts {
  const lg: Layout[] = [];
  const md: Layout[] = [];
  const sm: Layout[] = [];

  allPanels.forEach((item, index) => {
    const gridPos = getGridPos(item.panel);
    const constraints = getPanelConstraints(item.panel.type);
    const key = `panel-${index}`;

    // Desktop layout (24 cols)
    lg.push({
      i: key,
      x: gridPos.x ?? (index * 6) % 24,
      y: gridPos.y ?? Math.floor((index * 6) / 24) * 4,
      w: gridPos.w,
      h: gridPos.h,
      ...constraints,
    });

    // Tablet layout (6 cols) - scale down
    const mdW = Math.max(constraints.minW, Math.round((gridPos.w / 24) * 6));
    md.push({
      i: key,
      x: (index * 3) % 6,
      y: Math.floor((index * 3) / 6) * 4,
      w: Math.min(mdW, 6),
      h: gridPos.h,
      minW: Math.min(constraints.minW, 6),
      minH: constraints.minH,
      maxW: 6,
      maxH: constraints.maxH,
    });

    // Mobile layout (1 col) - stack vertically
    sm.push({
      i: key,
      x: 0,
      y: index * 4,
      w: 1,
      h: gridPos.h,
      minW: 1,
      minH: constraints.minH,
      maxW: 1,
      maxH: constraints.maxH,
      static: true, // Prevent dragging on mobile
    });
  });

  return { lg, md, sm };
}

