// Inner grid component that uses react-grid-layout
interface DashboardGridProps {
  allPanels: Array<{ panel: PanelDescriptor; groupIndex?: number; group?: DashboardGroup }>;
  gridColumns: DashboardGridColumns;
  onSubComponentUpdated: (subComponent: DashboardVisualizationComponent | null, index: number) => void;
  initialTimeSpan?: TimeSpan;
  initialFilterExpression?: string;
  initialLoading?: boolean;
  panelCollapseStates: Map<number, boolean>;
  onPanelCollapsedChange: (panelIndex: number, collapsed: boolean) => void;
  onChartSelection?: (timeSpan: TimeSpan, selection: { name: string; series: string; value: number }) => void;
  children?: React.ReactNode;
}

const DashboardGrid: React.FC<DashboardGridProps> = ({
  allPanels,
  gridColumns,
  onSubComponentUpdated,
  initialTimeSpan,
  initialFilterExpression,
  initialLoading,
  panelCollapseStates,
  onPanelCollapsedChange,
  onChartSelection,
  children,
}) => {
  const layoutContext = useDashboardLayoutOptional();

  // Generate default layouts from panel definitions
  const defaultLayouts = useMemo(
    () => generateLayoutsFromPanels(allPanels, gridColumns),
    [allPanels, gridColumns]
  );

  // Use context layouts if available, otherwise default
  const layouts = layoutContext?.layouts ?? defaultLayouts;
  const onLayoutChange = layoutContext?.onLayoutChange;

  // Breakpoint configuration
  const breakpoints = { lg: 1024, md: 768, sm: 0 };
  const cols = { lg: 24, md: 6, sm: 1 };

  return (
    <ResponsiveGridLayout
      className="layout"
      layouts={layouts}
      breakpoints={breakpoints}
      cols={cols}
      rowHeight={36}
      margin={[8, 8]}
      containerPadding={[0, 0]}
      onLayoutChange={onLayoutChange}
      draggableHandle=".dashboard-drag-handle"
      useCSSTransforms={true}
      compactType="vertical"
      preventCollision={false}
    >
      {allPanels.map((item, panelIndex) => {
        const isPanelCollapsed = panelCollapseStates.get(panelIndex) ?? item.panel.collapsed ?? false;

        return (
          <div key={`panel-${panelIndex}`} className="h-full">
            <DashboardGridPanel
              descriptor={item.panel}
              panelIndex={panelIndex}
              onSubComponentUpdated={onSubComponentUpdated}
              initialTimeSpan={initialTimeSpan}
              initialFilterExpression={initialFilterExpression}
              initialLoading={initialLoading}
              isCollapsed={isPanelCollapsed}
              onCollapsedChange={(collapsed) => onPanelCollapsedChange(panelIndex, collapsed)}
              onChartSelection={onChartSelection}
            />
          </div>
        );
      })}
      {children && (
        <div key="children-slot" data-grid={{ x: 0, y: 999, w: 24, h: 2, static: true }}>
          {children}
        </div>
      )}
    </ResponsiveGridLayout>
  );
};

