"use client";

import { cn } from "@/lib/utils";
import { connect } from "echarts";
import { ChevronRight } from "lucide-react";
import React, {
  createContext,
  forwardRef,
  useCallback,
  useContext,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { ResponsiveGridLayout, useContainerWidth } from 'react-grid-layout/react';
import type { Layout, ResponsiveLayouts as Layouts } from 'react-grid-layout';
import type { Dashboard, DashboardGroup, GridPos, PanelDescriptor } from "./dashboard-model";
import { useDashboardLayoutOptional } from './dashboard-layout-provider';
import { getPanelConstraints } from './dashboard-layout-constraints';
import type {
  DashboardVisualizationComponent,
  RefreshOptions,
} from "./dashboard-visualization-layout";
import { DashboardVisualizationPanel } from "./dashboard-visualization-panel";
import type { TimeSpan } from "./timespan-selector";

export interface DashboardPanelContainerRef {
  refresh: (timeSpan?: TimeSpan, filterExpression?: string) => void;
}

