     ```

   - **`src/components/shared/dashboard/dashboard-layout-constraints.ts`**
     - Defines min/max size constraints per panel type
     ```typescript
     export interface PanelConstraints {
       minW: number;
       minH: number;
       maxW: number;
       maxH: number;
     }

     const PANEL_CONSTRAINTS: Record<string, PanelConstraints> = {
       stat: { minW: 3, minH: 2, maxW: 12, maxH: 4 },
       table: { minW: 6, minH: 3, maxW: 24, maxH: 16 },
       line: { minW: 6, minH: 3, maxW: 24, maxH: 12 },
       // ... more types
     };

     export function getPanelConstraints(panelType: string): PanelConstraints { ... }
     ```

   - **`src/components/shared/dashboard/dashboard-layout-provider.tsx`**
     - React context provider for layout state with debounced saving
     ```typescript
     import type { Layout, ResponsiveLayouts } from 'react-grid-layout';

     interface DashboardLayoutContextValue {
       layouts: ResponsiveLayouts;
       onLayoutChange: (currentLayout: Layout, allLayouts: ResponsiveLayouts) => void;
       resetLayout: () => void;
       isEditing: boolean;
     }

     export function DashboardLayoutProvider({ dashboardId, defaultLayouts, children }: DashboardLayoutProviderProps) { ... }
     export function useDashboardLayout(): DashboardLayoutContextValue { ... }
     export function useDashboardLayoutOptional(): DashboardLayoutContextValue | null { ... }
     ```

   - **`src/components/shared/dashboard/dashboard-panel-container.tsx`**
     - Major rewrite to use ResponsiveGridLayout instead of CSS Grid
     ```typescript
     import { ResponsiveGridLayout, useContainerWidth, verticalCompactor } from 'react-grid-layout/react';
     import type { Layout, LayoutItem, ResponsiveLayouts } from 'react-grid-layout';

     const DashboardGrid: React.FC<DashboardGridProps> = ({ ... }) => {
       const layoutContext = useDashboardLayoutOptional();
       const { width, mounted, containerRef } = useContainerWidth();
       // ...
       return (
         <div ref={containerRef} className="w-full">
           {mounted && width > 0 && (
             <ResponsiveGridLayout
               width={width}
               layouts={layouts}
               breakpoints={{ lg: 1024, md: 768, sm: 0 }}
               cols={{ lg: 24, md: 6, sm: 1 }}
               rowHeight={36}
               dragConfig={{ enabled: true, bounded: false, handle: ".dashboard-drag-handle", threshold: 3 }}
               compactor={verticalCompactor}
             >
               {/* panels */}
             </ResponsiveGridLayout>
           )}
         </div>
       );
     };
     ```

   - **`src/components/shared/dashboard/dashboard-visualization-layout.tsx`**
     - Added drag handle class to panel headers
     ```typescript
     const headerContent = (
       <div className={cn(
         "flex items-center px-2 py-1 transition-colors dashboard-drag-handle",
         "cursor-grab active:cursor-grabbing",
         headerBackground && "bg-muted/50"
       )}>
     ```

   - **`src/components/shared/dashboard/dashboard-filter.tsx`**
     - Added `onResetLayout` prop and Reset Layout button
     ```typescript
     interface FilterProps {
       // ... existing props
       onResetLayout?: () => void;
